INSERT IGNORE INTO u_style_market
(biz_no, style_name, description, prompt_summary, prompt, scope, publisher_user_id, price, total_uses, weekly_uses, weekly_earnings, milestone_bonus, last_settlement_at, enable_status, audit_status, source_type, is_deleted, created_at, updated_at, created_by, updated_by)
VALUES
('SM202607200001', '小红书种草风', ' emoji 丰富、分段清爽、种草感强', '多用表情符号，短句分段，突出卖点与使用场景', '你擅长写小红书风格的种草文案。要求：1) 多用 emoji 点缀标题和正文；2) 句子简短，3-5 行为一段；3) 先讲痛点/场景，再引出产品卖点；4) 结尾用互动问句引导评论；5) 语言亲切，像闺蜜聊天。', '小红书,种草,产品推荐', 0, 0.20, 128, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200002', '公众号深度风', '逻辑严密、案例详实、适合长文', '层层递进，案例+数据支撑，结尾升华主题', '你擅长写微信公众号深度长文。要求：1) 开篇用热点或故事引入；2) 正文采用「观点+案例+数据」的结构；3) 段落之间有清晰过渡句；4) 金句与小结穿插；5) 结尾升华主题，给读者行动启发。', '公众号,深度,观点', 0, 0.20, 86, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200003', '今日头条资讯风', '标题吸睛、信息密度高、客观陈述', '标题带数字/冲突，正文倒金字塔结构', '你擅长写今日头条资讯体文章。要求：1) 标题包含数字、冲突或悬念；2) 导语概括核心事实；3) 正文按重要性递减排列；4) 多用短句和直接引语；5) 保持客观，避免情绪化表达。', '头条,资讯,热点', 0, 0.20, 215, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200004', '知乎干货风', '条理清晰、引用权威、结论明确', '用「总-分-总」结构，列点说明，引用数据', '你擅长写知乎高赞干货回答。要求：1) 开头直接给出结论；2) 用「第一/第二/第三」或编号列表展开；3) 引用数据、论文或权威案例增强可信度；4) 每段有核心句；5) 结尾总结并邀请读者补充。', '知乎,干货,问答', 0, 0.20, 67, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200005', '百家号故事风', '叙事曲折、口语化、强共鸣', '以人物故事为主线，情节有起伏，结尾点题', '你擅长写百家号故事文。要求：1) 用具体人物和场景开头；2) 故事有冲突、转折和高潮；3) 对话自然口语化；4) 细节描写增强代入感；5) 结尾回扣主题，引发共鸣。', '百家号,故事,情感', 0, 0.20, 92, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200006', '抖音短文案风', '节奏快、钩子强、适合口播', '前3秒抓眼球，多用反问和短句，引导点赞关注', '你擅长写抖音短视频口播文案。要求：1) 开头3秒抛出强钩子；2) 多用反问、设问和短句；3) 节奏快，信息密度高；4) 适时引导点赞/关注/评论；5) 结尾有记忆点或金句。', '抖音,短视频,口播', 0, 0.20, 342, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200007', 'B站解说风', '轻松玩梗、逻辑自洽、弹幕友好', '语言活泼，适度玩梗，关键处留弹幕互动点', '你擅长写B站视频解说/评论文案。要求：1) 语言轻松，适度玩梗和缩写；2) 逻辑清晰，有「起因-经过-结果」；3) 在关键观点处设置弹幕互动点；4) 多用「划重点」「说白了」等B站常用表达；5) 结尾引导一键三连。', 'B站,解说,视频', 0, 0.20, 54, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200008', '知识星球/专栏风', '系统性强、适合系列输出', '模块分明，概念+方法论+案例，便于收藏转发', '你擅长写知识付费专栏文章。要求：1) 用「问题-模型-方法-案例」结构；2) 概念定义清晰；3) 提供可落地的步骤清单；4) 金句和图表描述穿插；5) 结尾引导收藏和转发。', '专栏,知识付费,方法论', 0, 0.20, 39, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200009', '朋友圈轻文案风', '简短走心、配图感强、不打扰', '3-5行短句，情绪饱满，适合配图发圈', '你擅长写朋友圈轻文案。要求：1) 控制在3-6行；2) 情绪真挚但不煽情；3) 多用意象和场景描写；4) 适当留白；5) 结尾可带一句感悟或祝福。', '朋友圈,短文案,生活', 0, 0.20, 176, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0),
('SM202607200010', '商业品牌稿风', '高端大气、价值导向、适合公关', '用词考究，突出品牌理念与社会价值', '你擅长写品牌公关稿。要求：1) 用词考究，避免口语化；2) 突出品牌理念、技术创新或社会责任；3) 结构稳重：背景-行动-价值-展望；4) 引用高管发言或权威背书；5) 结尾呼应品牌使命。', '品牌,公关,商业', 0, 0.20, 28, 0, 0.00, 0.00, NULL, 1, 1, 3, 0, NOW(3), NOW(3), 0, 0);
